// Function to split the raw HTML into a WordPress-friendly JSON object
function formatForWordPress(rawHtml) {
  let htmlString = String(rawHtml).trim();

  // Find the very first heading to use as the Title
  const titleMatch = htmlString.match(/<h[1-6]>(.*?)<\/h[1-6]>/);

  let postTitle = "Untitled Draft";
  let postContent = htmlString;

  // Extract the title and remove it from the body content
  if (titleMatch) {
    postTitle = titleMatch[1].trim(); 
    postContent = htmlString.replace(titleMatch[0], '').trim(); 
  }

  return {
    title: postTitle,
    content: postContent,
    status: 'draft' 
  };
}

// ==========================================
// IMPLEMENTATION FOR NESTED API OUTPUT
// ==========================================

// 1. Grab the raw incoming JSON from the previous node
// (Assuming n8n syntax here. If the array is sitting at the root of your JSON:)
const incomingData = $input.item.json; 

let aiText = "";

try {
  // 2. Dig through the nested arrays/objects to find the exact text string
  // If the incoming data is the array itself:
  if (Array.isArray(incomingData)) {
    aiText = incomingData[0].content.parts[0].text;
  } 
  // If the array is wrapped inside another property (e.g., incomingData.message):
  else if (incomingData.content && incomingData.content.parts) {
    aiText = incomingData.content.parts[0].text;
  } 
  // Fallback just in case the structure is slightly different
  else {
    throw new Error("Unexpected JSON structure.");
  }
} catch (error) {
  // If it fails to find the path, output an error so the workflow doesn't crash silently
  return { 
    json: { 
      _error: "Could not locate the text at content.parts[0].text", 
      message: error.message 
    } 
  };
}

// 3. Run the extracted text through the formatting function
const wpPayload = formatForWordPress(aiText);

// 4. Return the beautifully formatted WordPress payload!
return { json: wpPayload };

